namespace ShipmentTracker.Client.Models;

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Cancelled
}

public class ShipmentDto
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime CreatedAt { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public string CustomerEmail { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public class CreateShipmentRequest
{
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public string CustomerEmail { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public DateTime? EstimatedDelivery { get; set; }
}

public class UpdateShipmentStatusRequest
{
    public int Id { get; set; }
    public ShipmentStatus NewStatus { get; set; }
}

public class TrackingResult
{
    public bool Found { get; set; }
    public ShipmentDto? Shipment { get; set; }
}

using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public interface IShipmentService
{
    Task<List<ShipmentDto>> GetAllShipmentsAsync();
    Task<TrackingResult> TrackShipmentAsync(string trackingNumber);
    Task<ShipmentDto> CreateShipmentAsync(CreateShipmentRequest request);
    Task UpdateStatusAsync(UpdateShipmentStatusRequest request);
}

using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ClientShipmentService(HttpClient http) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        return await http.GetFromJsonAsync<List<ShipmentDto>>("api/shipments") ?? [];
    }

    public async Task<TrackingResult> TrackShipmentAsync(string trackingNumber)
    {
        var response = await http.GetAsync($"api/shipments/track/{Uri.EscapeDataString(trackingNumber)}");
        if (response.IsSuccessStatusCode)
        {
            var shipment = await response.Content.ReadFromJsonAsync<ShipmentDto>();
            return new TrackingResult { Found = true, Shipment = shipment };
        }
        return new TrackingResult { Found = false };
    }

    public async Task<ShipmentDto> CreateShipmentAsync(CreateShipmentRequest request)
    {
        var response = await http.PostAsJsonAsync("api/shipments", request);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<ShipmentDto>()
            ?? throw new InvalidOperationException("Failed to deserialize created shipment.");
    }

    public async Task UpdateStatusAsync(UpdateShipmentStatusRequest request)
    {
        var response = await http.PutAsJsonAsync($"api/shipments/{request.Id}/status", request);
        response.EnsureSuccessStatusCode();
    }
}

