using System.ComponentModel.DataAnnotations;

namespace ShipmentTracker.Data;

public class Shipment
{
    public int Id { get; set; }

    [MaxLength(20)]
    public string TrackingNumber { get; set; } = string.Empty;

    [MaxLength(200)]
    public string Origin { get; set; } = string.Empty;

    [MaxLength(200)]
    public string Destination { get; set; } = string.Empty;

    public int Status { get; set; }

    public DateTime CreatedAt { get; set; }
    public DateTime? EstimatedDelivery { get; set; }

    [MaxLength(256)]
    public string CustomerEmail { get; set; } = string.Empty;

    [MaxLength(500)]
    public string Description { get; set; } = string.Empty;
}

using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ServerShipmentService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        return await db.Shipments
            .OrderByDescending(s => s.CreatedAt)
            .Select(s => MapToDto(s))
            .ToListAsync();
    }

    public async Task<TrackingResult> TrackShipmentAsync(string trackingNumber)
    {
        var shipment = await db.Shipments
            .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);

        if (shipment is null)
            return new TrackingResult { Found = false };

        return new TrackingResult { Found = true, Shipment = MapToDto(shipment) };
    }

    public async Task<ShipmentDto> CreateShipmentAsync(CreateShipmentRequest request)
    {
        var shipment = new Shipment
        {
            TrackingNumber = GenerateTrackingNumber(),
            Origin = request.Origin,
            Destination = request.Destination,
            CustomerEmail = request.CustomerEmail,
            Description = request.Description,
            Status = (int)ShipmentStatus.Pending,
            CreatedAt = DateTime.UtcNow,
            EstimatedDelivery = request.EstimatedDelivery
        };

        db.Shipments.Add(shipment);
        await db.SaveChangesAsync();

        return MapToDto(shipment);
    }

    public async Task UpdateStatusAsync(UpdateShipmentStatusRequest request)
    {
        var shipment = await db.Shipments.FindAsync(request.Id)
            ?? throw new InvalidOperationException($"Shipment {request.Id} not found.");

        shipment.Status = (int)request.NewStatus;
        await db.SaveChangesAsync();
    }

    private static ShipmentDto MapToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = (ShipmentStatus)s.Status,
        CreatedAt = s.CreatedAt,
        EstimatedDelivery = s.EstimatedDelivery,
        CustomerEmail = s.CustomerEmail,
        Description = s.Description
    };

    private static string GenerateTrackingNumber()
    {
        return $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(100000, 999999)}";
    }
}

using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentApi(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments").RequireAuthorization();

        group.MapGet("", async (IShipmentService service) =>
            Results.Ok(await service.GetAllShipmentsAsync()));

        group.MapGet("track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
        {
            var result = await service.TrackShipmentAsync(trackingNumber);
            return result.Found ? Results.Ok(result.Shipment) : Results.NotFound();
        }).AllowAnonymous();

        group.MapPost("", async (CreateShipmentRequest request, IShipmentService service) =>
        {
            var shipment = await service.CreateShipmentAsync(request);
            return Results.Created($"api/shipments/{shipment.Id}", shipment);
        });

        group.MapPut("{id}/status", async (int id, UpdateShipmentStatusRequest request, IShipmentService service) =>
        {
            request.Id = id;
            await service.UpdateStatusAsync(request);
            return Results.NoContent();
        });
    }
}

