arguments.file_text:
@page "/shipments"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Manage Shipments</PageTitle>

<h1>Shipments</h1>

<div class="mb-3">
    <button class="btn btn-success" @onclick="ShowCreateForm">+ New Shipment</button>
</div>

@if (showCreateForm)
{
    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title">Create Shipment</h5>
            <EditForm Model="newShipment" OnValidSubmit="CreateShipment" FormName="create-shipment">
                <DataAnnotationsValidator />
                <div class="row">
                    <div class="col-md-6 mb-2">
                        <label class="form-label">Origin</label>
                        <InputText class="form-control" @bind-Value="newShipment.Origin" />
                    </div>
                    <div class="col-md-6 mb-2">
                        <label class="form-label">Destination</label>
                        <InputText class="form-control" @bind-Value="newShipment.Destination" />
                    </div>
                </div>
                <div class="row">
                    <div class="col-md-6 mb-2">
                        <label class="form-label">Customer Email</label>
                        <InputText class="form-control" @bind-Value="newShipment.CustomerEmail" />
                    </div>
                    <div class="col-md-6 mb-2">
                        <label class="form-label">Estimated Delivery</label>
                        <InputDate class="form-control" @bind-Value="newShipment.EstimatedDelivery" />
                    </div>
                </div>
                <div class="mb-2">
                    <label class="form-label">Description</label>
                    <InputText class="form-control" @bind-Value="newShipment.Description" />
                </div>
                <button type="submit" class="btn btn-primary me-2">Create</button>
                <button type="button" class="btn btn-secondary" @onclick="CancelCreate">Cancel</button>
            </EditForm>
        </div>
    </div>
}

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (shipments.Count == 0)
{
    <p>No shipments found. Create one to get started.</p>
}
else
{
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Filter by destination or tracking #..."
               @bind="filterText" @bind:event="oninput" />
    </div>

    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in FilteredShipments)
                {
                    <tr>
                        <td><code>@shipment.TrackingNumber</code></td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></td>
                        <td>@shipment.EstimatedDelivery?.ToString("yyyy-MM-dd")</td>
                        <td>
                            <select class="form-select form-select-sm d-inline-block w-auto"
                                    @onchange="e => UpdateStatus(shipment, e)">
                                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                {
                                    <option value="@((int)status)" selected="@(status == shipment.Status)">@status</option>
                                }
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private CreateShipmentRequest newShipment = new();
    private bool showCreateForm;
    private string filterText = string.Empty;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments?.Where(s =>
            string.IsNullOrWhiteSpace(filterText) ||
            s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
            s.Origin.Contains(filterText, StringComparison.OrdinalIgnoreCase))
        ?? [];

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private void ShowCreateForm() => showCreateForm = true;
    private void CancelCreate() => showCreateForm = false;

    private async Task CreateShipment()
    {
        await ShipmentService.CreateShipmentAsync(newShipment);
        newShipment = new();
        showCreateForm = false;
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (int.TryParse(e.Value?.ToString(), out var statusValue))
        {
            var newStatus = (ShipmentStatus)statusValue;
            await ShipmentService.UpdateStatusAsync(new UpdateShipmentStatusRequest
            {
                Id = shipment.Id,
                NewStatus = newStatus
            });
            shipment.Status = newStatus;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row justify-content-center mt-4">
    <div class="col-md-8">
        <div class="input-group mb-3">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g., SHP-20260522-123456)"
                   @bind="trackingNumber" @bind:event="oninput"
                   @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="TrackShipment" disabled="@isLoading">
                @if (isLoading)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Track
            </button>
        </div>

        @if (searched && result is not null && !result.Found)
        {
            <div class="alert alert-warning">
                <strong>Not found.</strong> No shipment matches tracking number <code>@searchedNumber</code>.
            </div>
        }

        @if (result?.Found == true && result.Shipment is not null)
        {
            var s = result.Shipment;
            <div class="card">
                <div class="card-header d-flex justify-content-between align-items-center">
                    <strong>@s.TrackingNumber</strong>
                    <span class="badge @GetStatusBadgeClass(s.Status) fs-6">@s.Status</span>
                </div>
                <div class="card-body">
                    <div class="row">
                        <div class="col-md-6">
                            <p><strong>From:</strong> @s.Origin</p>
                            <p><strong>To:</strong> @s.Destination</p>
                            <p><strong>Description:</strong> @s.Description</p>
                        </div>
                        <div class="col-md-6">
                            <p><strong>Shipped:</strong> @s.CreatedAt.ToString("yyyy-MM-dd")</p>
                            <p><strong>Estimated Delivery:</strong>
                                @(s.EstimatedDelivery?.ToString("yyyy-MM-dd") ?? "TBD")</p>
                        </div>
                    </div>

                    <hr />
                    <h6>Shipment Progress</h6>
                    <div class="progress" style="height: 30px;">
                        <div class="progress-bar @GetProgressBarClass(s.Status)"
                             role="progressbar"
                             style="width: @(GetProgressPercent(s.Status))%">
                            @s.Status
                        </div>
                    </div>
                </div>
            </div>
        }
    </div>
</div>

@code {
    private string trackingNumber = string.Empty;
    private string searchedNumber = string.Empty;
    private TrackingResult? result;
    private bool searched;
    private bool isLoading;

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isLoading = true;
        searchedNumber = trackingNumber.Trim();
        result = await ShipmentService.TrackShipmentAsync(searchedNumber);
        searched = true;
        isLoading = false;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Cancelled => 100,
        _ => 0
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-primary"
    };

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

